import anthropic, dataclasses, time

# Haiku 4.5 rates (USD per million tokens) — update when pricing changes
MODEL_COST = {
    "claude-haiku-4-5-20251001": {"input": 0.80, "output": 4.00},
    "claude-sonnet-4-6": {"input": 3.00, "output": 15.00},
}

@dataclasses.dataclass
class CostTracker:
    model: str
    input_tokens: int = 0
    output_tokens: int = 0
    llm_calls: int = 0
    tool_calls: int = 0
    start_time: float = dataclasses.field(default_factory=time.monotonic)

    def record(self, usage: anthropic.types.Usage) -> None:
        self.input_tokens += usage.input_tokens
        self.output_tokens += usage.output_tokens
        self.llm_calls += 1

    @property
    def cost_usd(self) -> float:
        rates = MODEL_COST.get(self.model, {"input": 0, "output": 0})
        return (
            self.input_tokens / 1_000_000 * rates["input"]
            + self.output_tokens / 1_000_000 * rates["output"]
        )

    @property
    def elapsed_s(self) -> float:
        return time.monotonic() - self.start_time

    def summary(self) -> dict:
        return {
            "model": self.model,
            "llm_calls": self.llm_calls,
            "tool_calls": self.tool_calls,
            "input_tokens": self.input_tokens,
            "output_tokens": self.output_tokens,
            "cost_usd": round(self.cost_usd, 6),
            "elapsed_s": round(self.elapsed_s, 2),
            "tokens_per_dollar": round(
                (self.input_tokens + self.output_tokens) / self.cost_usd
            ) if self.cost_usd > 0 else 0,
        }

# Example agent loop that records cost
def run_agent_with_cost_tracking(task: str, model: str = "claude-haiku-4-5-20251001") -> dict:
    client = anthropic.Anthropic()
    tracker = CostTracker(model=model)
    messages = [{"role": "user", "content": task}]

    tools = [
        {
            "name": "calculator",
            "description": "Evaluate a mathematical expression.",
            "input_schema": {
                "type": "object",
                "properties": {"expression": {"type": "string"}},
                "required": ["expression"],
            },
        }
    ]

    for step in range(10):
        resp = client.messages.create(
            model=model,
            max_tokens=512,
            tools=tools,
            messages=messages,
        )
        tracker.record(resp.usage)

        if resp.stop_reason == "end_turn":
            break

        if resp.stop_reason == "tool_use":
            tool_results = []
            for block in resp.content:
                if block.type == "tool_use":
                    tracker.tool_calls += 1
                    expr = block.input.get("expression", "0")
                    try:
                        result = str(eval(expr, {"__builtins__": {}}))
                    except Exception as e:
                        result = f"Error: {e}"
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": tool_results},
            ]

    final_text = " ".join(b.text for b in resp.content if hasattr(b, "text"))
    return {"answer": final_text, "cost": tracker.summary()}

result = run_agent_with_cost_tracking("What is (123 * 456) + (789 / 3)?")
import json
print(json.dumps(result["cost"], indent=2))

import anthropic, time, dataclasses
from contextlib import contextmanager

@dataclasses.dataclass
class LatencySpan:
    name: str
    duration_ms: float

@dataclasses.dataclass
class LatencyProfile:
    total_ms: float
    spans: list[LatencySpan]

    def breakdown(self) -> dict[str, float]:
        by_category: dict[str, float] = {}
        for span in self.spans:
            category = span.name.split(":")[0]
            by_category[category] = by_category.get(category, 0) + span.duration_ms
        return by_category

    def pct(self, category: str) -> float:
        total = sum(self.breakdown().values())
        return self.breakdown().get(category, 0) / total * 100 if total else 0

def profile_agent_run(task: str) -> tuple[str, LatencyProfile]:
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": task}]
    spans: list[LatencySpan] = []
    start_total = time.monotonic()

    tools = [
        {
            "name": "search",
            "description": "Search for information.",
            "input_schema": {
                "type": "object",
                "properties": {"query": {"type": "string"}},
                "required": ["query"],
            },
        }
    ]

    def fake_search(query: str) -> str:
        time.sleep(0.15)   # simulate 150ms tool latency
        return f"Results for '{query}': [example data]"

    final_text = ""
    for step in range(8):
        t0 = time.monotonic()
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=256,
            tools=tools,
            messages=messages,
        )
        spans.append(LatencySpan("llm", (time.monotonic() - t0) * 1000))

        if resp.stop_reason == "end_turn":
            final_text = " ".join(b.text for b in resp.content if hasattr(b, "text"))
            break

        if resp.stop_reason == "tool_use":
            tool_results = []
            for block in resp.content:
                if block.type == "tool_use":
                    t1 = time.monotonic()
                    result = fake_search(block.input.get("query", ""))
                    spans.append(LatencySpan("tool", (time.monotonic() - t1) * 1000))
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": tool_results},
            ]

    profile = LatencyProfile(
        total_ms=(time.monotonic() - start_total) * 1000,
        spans=spans,
    )
    return final_text, profile

answer, profile = profile_agent_run("Find information about renewable energy.")
bd = profile.breakdown()
print(f"Total: {profile.total_ms:.0f}ms")
for cat, ms in bd.items():
    print(f"  {cat:6s}: {ms:.0f}ms ({profile.pct(cat):.0f}%)")

