import dataclasses, anthropic, time

@dataclasses.dataclass
class Budget:
    max_cost_usd: float | None = None
    max_latency_s: float | None = None
    max_steps: int | None = None

@dataclasses.dataclass
class BudgetResult:
    passed: bool
    violations: list[str]
    cost_usd: float
    latency_s: float
    steps: int

MODEL_RATES = {"claude-haiku-4-5-20251001": {"input": 0.80e-6, "output": 4.00e-6}}

def check_budget(budget: Budget, cost_usd: float, latency_s: float, steps: int) -> BudgetResult:
    violations = []
    if budget.max_cost_usd is not None and cost_usd > budget.max_cost_usd:
        violations.append(f"cost ${cost_usd:.4f} > budget ${budget.max_cost_usd:.4f}")
    if budget.max_latency_s is not None and latency_s > budget.max_latency_s:
        violations.append(f"latency {latency_s:.1f}s > budget {budget.max_latency_s:.1f}s")
    if budget.max_steps is not None and steps > budget.max_steps:
        violations.append(f"steps {steps} > budget {budget.max_steps}")
    return BudgetResult(
        passed=len(violations) == 0,
        violations=violations,
        cost_usd=cost_usd,
        latency_s=latency_s,
        steps=steps,
    )

def run_with_budget(task: str, budget: Budget, model: str = "claude-haiku-4-5-20251001") -> BudgetResult:
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": task}]
    rates = MODEL_RATES.get(model, {"input": 0, "output": 0})
    total_input = total_output = steps = 0
    start = time.monotonic()

    for _ in range(budget.max_steps or 20):
        resp = client.messages.create(
            model=model, max_tokens=256, messages=messages
        )
        total_input += resp.usage.input_tokens
        total_output += resp.usage.output_tokens
        steps += 1

        if resp.stop_reason == "end_turn":
            break

        messages += [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": "Continue."},
        ]

        # Check budget mid-run — abort early if already exceeded
        elapsed = time.monotonic() - start
        cost_so_far = total_input * rates["input"] + total_output * rates["output"]
        if budget.max_cost_usd and cost_so_far > budget.max_cost_usd:
            return check_budget(budget, cost_so_far, elapsed, steps)
        if budget.max_latency_s and elapsed > budget.max_latency_s:
            return check_budget(budget, cost_so_far, elapsed, steps)

    final_cost = total_input * rates["input"] + total_output * rates["output"]
    return check_budget(budget, final_cost, time.monotonic() - start, steps)

budget = Budget(max_cost_usd=0.005, max_latency_s=15.0, max_steps=5)
result = run_with_budget("Summarise the history of computing in one paragraph.", budget)
print(f"Passed: {result.passed}")
print(f"Cost: ${result.cost_usd:.5f} | Latency: {result.latency_s:.1f}s | Steps: {result.steps}")
if result.violations:
    print("Violations:", result.violations)
